import pytest

def test_create_team_name_minimum_length_one_char(manager_session):
    payload = {
        "name": "X",
        "department": "Engineering",
        "manager_id": manager_session.user_id
    }
    resp = manager_session.post("/api/teams", json=payload)
    assert resp.status_code in (200, 201), (
        f"1-char name should be accepted; got {resp.status_code}"
    )
    body = resp.json()
    assert body.get("id"), "Response must contain a non-empty 'id' for min-length name"

