def test_create_team_unauthenticated_returns_401(anonymous_session):
    payload = {
        "name": "Ghost Team",
        "department": "Engineering",
        "manager_id": "some-manager-id"
    }
    resp = anonymous_session.post("/api/teams", json=payload)
    assert resp.status_code == 401, f"Expected 401, got {resp.status_code}"

